async (params, browser) => {
  // Open Jira issue
  await browser.open(`${params.jira_url}/browse/${params.issue_key}`)

  // Let page load
  await browser.wait(2000)

  // Add comment via REST API
  const result = await browser.evaluate(`const baseUrl = params.jira_url.replace(/\/$/, ''); const body = { body: { type: 'doc', version: 1, content: [{ type: 'paragraph', content: [{ type: 'text', text: params.comment }] }] } }; const resp = await fetch(baseUrl + '/rest/api/3/issue/' + params.issue_key + '/comment', { method: 'POST', headers: { 'Content-Type': 'application/json' }, credentials: 'same-origin', body: JSON.stringify(body) }); if (!resp.ok) { const err = await resp.text(); throw new Error('Comment failed: ' + resp.status + ' ' + err); } const result = await resp.json(); return { success: true, key: '' + params.issue_key + '', comment_id: result.id, author: result.author?.displayName || '' }`)

  return result
}
